import java.util.Scanner;

public class SecureBuffer {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");

        // Read user input as a line to handle spaces
        String userInput = scanner.nextLine();

        // Creating a fixed-size character array with a safe buffer size
        int bufferSize = Math.min(userInput.length(), 10); // Limit buffer size to prevent overflow
        char[] buffer = new char[bufferSize];

        // Copying the user input into the buffer safely
        userInput.getChars(0, bufferSize, buffer, 0);

        System.out.println("Buffer contents: " + new String(buffer));
    }
}

